function [ttlA,ttlS,lblP] = fLabelEsmovV03(nmbStep)%% function label for esm overview%% [ttlA,ttlS,lblP] = fLabelEsmovV01()% gives you labels%% ttlA: title for angle text output% ttlS: title for spectrumd text output% lblP: lable for image plot%% Kei Nakamura% Created on Tuesday, December 7th 2010.% Modified on %% ver.1:% ver.2: Friday, February 24th, 2012% add div for each energy (FWHM)% add div for each energy (rms)%% main body%% label for angle txt outputttlA = cell(5*nmbStep,1);ttlA{1} = 'angle_mrad';ttlA{2} = 'charge_pC/mrad';ttlA{3} = 'charge+std_pC/mrad';ttlA{4} = 'charge-std_pC/mrad';ttlA{5} = 'std_pC/mrad';%% label for energy txt outputttlS = cell(8*nmbStep,1);ttlS{1} = 'energy_MeV';ttlS{2} = 'charge_pC/MeV';ttlS{3} = 'charge+std_pC/MeV';ttlS{4} = 'charge-std_pC/MeV';ttlS{5} = 'std_pC/MeV';ttlS{6} = 'mrad(FWHM)';ttlS{7} = 'mrad(rms)';ttlS{8} = 'mrad(mean)';for ii=1:nmbStep-1    ttlA(ii*5+1:(ii+1)*5) = ttlA(1:5);    ttlS(ii*8+1:(ii+1)*8) = ttlS(1:8);end%% label for plotlblP{1} = 'mrad';lblP{2} = 'MeV';
